catalog_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
   if (isLoading) {
      return;
   }
   var validation = validateQuantity(newValue);
    if (!validation.valid) {
        g_form.showFieldMsg('quantity_needed', validation.message, 'error');
        return;

    }
	var qty = validation.value;
    g_form.hideFieldMsg('quantity_needed');

   var medicine = g_form.getValue('medicine_name');

    if (medicine === '') {
        g_form.showFieldMsg('medicine_name', 'Please select a medicine before entering the quantity.', 'error');
    } else {

		var ga = new GlideAjax('x_1971078_smart_0.MedicineScripts');
		ga.addParam('sysparm_name', 'checkAvailability');
		ga.addParam('sysparm_medicine', medicine);
		ga.addParam('sysparm_quantity', qty);

		g_form.clearValue('check_availability');
		ga.getXMLAnswer(function(res) {
			console.log(res);
			g_form.clearValue('check_availability');
			if (res === 'true') {				
				g_form.setValue('check_availability', 'Yes');
			} else {
				g_form.showFieldMsg('quantity_needed', 'The requested quantity is currently unavailable in our stock.', 'error');
				g_form.setValue('check_availability', 'No');
			}
		});

		var unitPriceString  = g_form.getValue('unit_price').replace(/[^0-9.-]/g, '');
		var unitPrice = parseFloat(unitPriceString);
		var totalPrice = qty * unitPrice;
		g_form.setValue('subtotal_price', totalPrice.toString() + ' EGP');

    }


	function validateQuantity(value) {
    if (typeof value === 'string') value = value.trim();
    else value = String(value).trim();

    if (value === '') {
        return { valid: false, message: '⚠️ Please enter a quantity.' };
    }

    if (!/^[0-9]+$/.test(value)) {
        return { valid: false, message: '⛔ Quantity must be a number.' };
    }

    var qty = parseInt(value, 10);

    if (qty <= 0) {
        return { valid: false, message: '⚠️ Quantity must be greater than zero.' };
    }

    if (qty > 999) {
        return { valid: false, message: '⛔ Maximum quantity allowed is 999.' };
    }

    return { valid: true, value: qty };
}

}
